SELECT count(*) FROM role_type, cast_info, name, title, aka_name, char_name, movie_companies, kind_type WHERE cast_info.role_id = role_type.id AND cast_info.person_id = name.id AND cast_info.movie_id = title.id AND aka_name.person_id = name.id AND cast_info.person_role_id = char_name.id AND movie_companies.movie_id = title.id AND title.kind_id = kind_type.id;